import sailpoint.object.ResourceObject;
import sailpoint.api.SailPointContext;
import java.util.Map;

// Javadoc Spec: context represents sailpoint.api.SailPointContext
// Javadoc Spec: object represents sailpoint.object.ResourceObject aggregated attributes
// Javadoc Spec: application represents sailpoint.object.Application source configuration

if (object != null) {
    String email = (String) object.getAttribute("EmailID");
    String secondCol = (String) object.getAttribute("SecondColumn");
    if (email != null && secondCol != null) {
        // Concatenate Email ID (first column) and the second column during flat file aggregation
        object.setAttribute("EmailID", email + "_" + secondCol);
    }
}
return object;
